#pragma warning disable CS1591, CS1573
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
namespace 
{
    [ApiController]
    [Route("api/[controller]")]
    public class ItemController : ControllerBase
    {
        private readonly global::IItemService iItemService;
        public ItemController(global::IItemService iItemService)
        {
            this.iItemService = iItemService;
        }

        [Route("FindItem/{id}")]
        [HttpGet]
        [global::CustomAttr]
        public string FindItem([FromRoute] int id)
        {
            return this.iItemService.FindItem(id);                    
        }
    }
}
